questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(3)+1;

/* ===== Component values ===== */
R_val:  if set=1 then 200  else if set=2 then 1000 else 500;
L_val:  1;
C_val:  1e-6;
Is_val: 10e-3;
V0_val: if set=1 then 20 else if set=2 then 5 else 15;
I0_val: if set=2 then 3e-3 else 0;

/* ===== Damping parameters (parallel RLC) ===== */
ta_alpha:  float(1/(2*R_val*C_val));
ta_omega0: float(1/sqrt(L_val*C_val));
disc: float(ta_alpha^2 - ta_omega0^2);

/* ===== Regime classification ===== */
/* 1=overdamped, 2=underdamped, 3=critically damped */
ta_regime: if abs(ta_alpha-ta_omega0) < 1.0 then 3
           else if disc > 0 then 1
           else 2;
regime_name: if ta_regime=1 then "overdamped"
             else if ta_regime=2 then "underdamped"
             else "critically damped";

/* ===== Damped frequency / root separation ===== */
ta_omegad: float(sqrt(abs(disc)));

/* ===== Final value ===== */
ta_If: float(Is_val);

/* ===== Characteristic roots ===== */
s1_r: if ta_regime=1 then float(-ta_alpha+sqrt(disc)) else float(-ta_alpha);
s2_r: if ta_regime=1 then float(-ta_alpha-sqrt(disc)) else float(-ta_alpha);

/* ===== Coefficients for iL(t) = If + natural response ===== */
/* Initial conditions: iL(0+)=I0, diL/dt(0+)=V0/L               */
/* Overdamped: If+A1'+A2'=I0,  s1*A1'+s2*A2'=V0/L               */
ta_A1p: if ta_regime=1 then float((V0_val/L_val - s2_r*(I0_val-ta_If))/(s1_r-s2_r)) else 0;
ta_A2p: if ta_regime=1 then float(I0_val-ta_If-ta_A1p) else 0;

/* Underdamped: If+B1'=I0, -alpha*B1'+omegad*B2'=V0/L            */
ta_B1p: if ta_regime=2 then float(I0_val-ta_If) else 0;
ta_B2p: if ta_regime=2 then float((V0_val/L_val+ta_alpha*ta_B1p)/ta_omegad) else 0;

/* Critically damped: If+D2'=I0, D1'-alpha*D2'=V0/L              */
ta_D2p: if ta_regime=3 then float(I0_val-ta_If) else 0;
ta_D1p: if ta_regime=3 then float(V0_val/L_val+ta_alpha*ta_D2p) else 0;

/* ===== iL(t) complete ===== */
ta_iL: if ta_regime=1 then ta_If + ta_A1p*exp(s1_r*t) + ta_A2p*exp(s2_r*t)
       else if ta_regime=2 then ta_If + exp(-ta_alpha*t)*(ta_B1p*cos(ta_omegad*t)+ta_B2p*sin(ta_omegad*t))
       else ta_If + (ta_D1p*t+ta_D2p)*exp(-ta_alpha*t);

/* ===== v(t) = L * d(iL)/dt ===== */
ta_v: ev(L_val*diff(ta_iL, t), simp);

/* ===== FVT check value ===== */
ta_fvt: float(ta_If);

/* ===== Teacher answers ===== */
ta1: 1;
ta2: ta_If;
ta3: ta_regime;

/* Part (d): general form with symbolic constants */
ta4: if ta_regime=1 then ta_If + A1*exp(s1_r*t) + A2*exp(s2_r*t)
     else if ta_regime=2 then ta_If + exp(-ta_alpha*t)*(B1*cos(ta_omegad*t)+B2*sin(ta_omegad*t))
     else ta_If + (D1*t+D2)*exp(-ta_alpha*t);

ta5: ta_iL;
ta6: ta_v;
ta7: ta_fvt;

/* ===== Numerical sampling for expression PRTs ===== */
t_test1: 1.0e-4;
t_test2: 5.0e-4;
t_test3: 1.0e-3;
ta5_at_t1: float(subst(t=t_test1, ta5));
ta5_at_t2: float(subst(t=t_test2, ta5));
ta5_at_t3: float(subst(t=t_test3, ta5));
ta6_at_t1: float(subst(t=t_test1, ta6));
ta6_at_t2: float(subst(t=t_test2, ta6));
ta6_at_t3: float(subst(t=t_test3, ta6));

feedbackvariables.text:
dvdt0: float(V0_val/L_val);
sa5_at_t1: float(subst(t=t_test1, ans5));
sa5_at_t2: float(subst(t=t_test2, ans5));
sa5_at_t3: float(subst(t=t_test3, ans5));
rerr5_1: if abs(ta5_at_t1) > 1.0e-10 then abs((sa5_at_t1 - ta5_at_t1)/ta5_at_t1) else abs(sa5_at_t1 - ta5_at_t1);
rerr5_2: if abs(ta5_at_t2) > 1.0e-10 then abs((sa5_at_t2 - ta5_at_t2)/ta5_at_t2) else abs(sa5_at_t2 - ta5_at_t2);
rerr5_3: if abs(ta5_at_t3) > 1.0e-10 then abs((sa5_at_t3 - ta5_at_t3)/ta5_at_t3) else abs(sa5_at_t3 - ta5_at_t3);
iL_num_ok: if rerr5_1 < 0.05 and rerr5_2 < 0.05 and rerr5_3 < 0.05 then true else false;

sa6_at_t1: float(subst(t=t_test1, ans6));
sa6_at_t2: float(subst(t=t_test2, ans6));
sa6_at_t3: float(subst(t=t_test3, ans6));
rerr6_1: if abs(ta6_at_t1) > 1.0e-10 then abs((sa6_at_t1 - ta6_at_t1)/ta6_at_t1) else abs(sa6_at_t1 - ta6_at_t1);
rerr6_2: if abs(ta6_at_t2) > 1.0e-10 then abs((sa6_at_t2 - ta6_at_t2)/ta6_at_t2) else abs(sa6_at_t2 - ta6_at_t2);
rerr6_3: if abs(ta6_at_t3) > 1.0e-10 then abs((sa6_at_t3 - ta6_at_t3)/ta6_at_t3) else abs(sa6_at_t3 - ta6_at_t3);
vt_num_ok: if rerr6_1 < 0.05 and rerr6_2 < 0.05 and rerr6_3 < 0.05 then true else false;
